function Card({ children, style, onClick }) {
  const base = { background:C.white, borderRadius:16, boxShadow:`0 2px 12px ${C.shadow}`, padding:16, ...style };
  return <div style={base} onClick={onClick} onMouseEnter={e=>{if(onClick)e.currentTarget.style.boxShadow=`0 4px 20px ${C.shadow}`;}} onMouseLeave={e=>{if(onClick)e.currentTarget.style.boxShadow=`0 2px 12px ${C.shadow}`;}}>{children}</div>;
}

function Btn({ children, onClick, variant, small, style, disabled }) {
  const v = variant||"primary";
  const base = { border:"none", borderRadius:10, fontFamily:"inherit", cursor:disabled?"not-allowed":"pointer", display:"flex", alignItems:"center", gap:6, padding:small?"6px 12px":"10px 20px", fontSize:small?12:13, fontWeight:700, opacity:disabled?0.5:1, transition:"all 0.18s", ...style };
  const variants = { primary:{background:C.blue,color:C.white}, success:{background:C.green,color:C.white}, danger:{background:C.red,color:C.white}, ghost:{background:"transparent",color:C.navy,border:`1.5px solid ${C.grayLt}`}, teal:{background:C.teal,color:C.white}, amber:{background:C.amber,color:C.white}, purple:{background:C.purple,color:C.white} };
  return <button style={{...base,...variants[v]}} onClick={disabled?undefined:onClick} onMouseEnter={e=>{if(!disabled)e.currentTarget.style.opacity="0.85";}} onMouseLeave={e=>{e.currentTarget.style.opacity="1";}}>{children}</button>;
}

function PBar({ value, max, color, h }) {
  const pct = Math.min(100, ((value||0)/(max||100))*100);
  return <div style={{background:C.grayLt,borderRadius:99,height:h||10,overflow:"hidden"}}><div style={{width:`${pct}%`,height:"100%",background:color||C.blue,borderRadius:99,transition:"width 0.5s"}}></div></div>;
}

function Bdg({ text, color }) {
  return <span style={{background:(color||C.blue)+"1A",color:color||C.blue,borderRadius:99,padding:"2px 10px",fontSize:11,fontWeight:700}}>{text}</span>;
}

function StatCard({ label, value, icon, color, sub }) {
  return <Card><div style={{fontSize:22,marginBottom:4}}>{icon}</div><div style={{fontSize:22,fontWeight:900,color:color||C.navy,lineHeight:1}}>{value}</div>{sub&&<div style={{fontSize:10,color:C.gray,marginTop:2}}>{sub}</div>}<div style={{fontSize:11,color:C.gray,marginTop:4}}>{label}</div></Card>;
}

// ── Vitals Trend ──────────────────────────────────────────────────────────────
function VitalsTrend({ vitalHistory }) {
  if (!vitalHistory || vitalHistory.length === 0) return null;
  const latest = vitalHistory[vitalHistory.length - 1];
  const hrNums = vitalHistory.map(v => parseInt(v.hr)||0);
  const maxHR = Math.max(...hrNums, 1);
  return (
    <Card style={{marginBottom:14,borderTop:`3px solid ${C.teal}`}}>
      <div style={{fontWeight:700,color:C.navy,marginBottom:12,fontSize:14}}>📊 العلامات الحيوية</div>
      <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:10,marginBottom:14}}>
        {[
          {label:"معدل القلب",value:`${latest.hr}`,unit:"نبضة/د",icon:"❤️",color:parseInt(latest.hr)>120?C.red:C.green},
          {label:"ضغط الدم",value:latest.bp,icon:"🩺",color:C.blue},
          {label:"الأكسجين",value:`${latest.spo2}%`,icon:"🫁",color:parseInt(latest.spo2)<95?C.red:C.teal},
        ].map((v,i)=>(
          <div key={i} style={{background:C.grayBg,borderRadius:12,padding:"12px 8px",textAlign:"center"}}>
            <div style={{fontSize:22,marginBottom:4}}>{v.icon}</div>
            <div style={{fontWeight:900,fontSize:18,color:v.color,lineHeight:1}}>{v.value}</div>
            <div style={{fontSize:10,color:C.gray,marginTop:3}}>{v.label}</div>
          </div>
        ))}
      </div>
      {vitalHistory.length > 1 && (
        <div>
          <div style={{fontSize:11,fontWeight:700,color:C.navy,marginBottom:8}}>سجل القراءات</div>
          <div style={{overflowX:"auto"}}>
            <div style={{display:"flex",gap:8,minWidth:"max-content",paddingBottom:4}}>
              {vitalHistory.map((v,i)=>{
                const hrVal = parseInt(v.hr)||0;
                const barH = Math.max(8, (hrVal/maxHR)*60);
                const isHigh = hrVal > 120;
                return (
                  <div key={i} style={{display:"flex",flexDirection:"column",alignItems:"center",gap:2}}>
                    <div style={{fontSize:9,color:isHigh?C.red:C.green,fontWeight:700}}>{v.hr}</div>
                    <div style={{width:32,height:60,background:C.grayLt,borderRadius:6,display:"flex",alignItems:"flex-end"}}>
                      <div style={{width:"100%",height:barH,background:isHigh?C.red:C.teal,borderRadius:6}}></div>
                    </div>
                    <div style={{fontSize:9,color:C.gray}}>{v.label||`قراءة ${i+1}`}</div>
                    <div style={{fontSize:8,color:parseInt(v.spo2)<95?C.red:C.green}}>{v.spo2}%</div>
                  </div>
                );
              })}
            </div>
          </div>
        </div>
      )}
    </Card>
  );
}

