      <div style={{display:"flex",alignItems:"center",gap:6,flexShrink:0}}>
        {currentUser && <span style={{fontSize:10,color:"rgba(255,255,255,.65)",maxWidth:80,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{currentUser.name}</span>}
        {onLogout && <Btn small variant="danger" style={{fontSize:10,padding:"4px 10px"}} onClick={onLogout}>خروج</Btn>}
      </div>
